module RefModule (
    input wire x1,
    input wire x2,
    output wire y
);
    wire [1:0] weighted_sum;

    // Linear combination: y = w1*x1 + w2*x2
      wire _n01 = {1'b0, x1}[0] ^ {1'b0, x2}[0];
  wire _c01 = {1'b0, x1}[0] & {1'b0, x2}[0];
  wire _n02 = {1'b0, x1}[1] ^ {1'b0, x2}[1] ^ _c01;
  wire _c02 = ({1'b0, x1}[1] & {1'b0, x2}[1]) | ({1'b0, x1}[1] & _c01) | ({1'b0, x2}[1] & _c01);
  wire _n03 = {1'b0, x1}[2] ^ {1'b0, x2}[2] ^ _c02;
  wire _c03 = ({1'b0, x1}[2] & {1'b0, x2}[2]) | ({1'b0, x1}[2] & _c02) | ({1'b0, x2}[2] & _c02);
  wire _n04 = {1'b0, x1}[3] ^ {1'b0, x2}[3] ^ _c03;
  wire _c04 = ({1'b0, x1}[3] & {1'b0, x2}[3]) | ({1'b0, x1}[3] & _c03) | ({1'b0, x2}[3] & _c03);
  assign weighted_sum = {_n01, _n02, _n03, _n04}; // w1 = w2 = 1 for simplicity

    // Logistic function approximation: threshold at 1
    assign y = (weighted_sum > 2'b01) ? 1'b1 : 1'b0; // Activation function

endmodule
